create table invoice_adjustments (
    adjustment_id   number generated by default as identity not null enable,
    invoice_id      varchar2(30 byte),
    adjustment_type varchar2(20 byte),
    description     varchar2(500 byte),
    amount          number(12, 2),
    promo_id        varchar2(30 byte),
    created_at      date default sysdate,
    created_by      varchar2(200 byte)
);

alter table invoice_adjustments add primary key ( adjustment_id )
    using index enable;

